}

int slow_add(int x, int y)
  /*@ Require
        0 <= x && x <= 100 && 
        0 <= y && y <= 100 && emp
      Ensure
        __return == x + y && emp
   */
{
  /*@ Inv
        0 <= x && x <= 100 && 
        0 <= y && y <= 200 &&
        x + y == x@pre + y@pre && emp
   */
  while (x > 0) {
    x = x - 1;
    y = y + 1;
  }
  return y;
}

